class AuthManager:
    """Handles player authentication with HMAC-based tokens."""

    def __init__(self, secret: str):
        self._secret = secret.encode('utf-8')
        self._registered_users: dict[str, str] = {}  # username -> password_hash
        self._active_tokens: dict[str, tuple[str, float]] = {}  # token -> (player_id, expiry)

    def register(self, username: str, password: str) -> Optional[str]:
        if not username or not password:
            return None
        if len(username) > MAX_NAME_LENGTH:
            return None
        # Sanitize username
        sanitized = ''.join(c for c in username if c.isalnum() or c in '-_')
        if not sanitized or sanitized != username:
            return None
        if sanitized in self._registered_users:
            return None
        # Hash password with salt
        salt = secrets.token_hex(16)
        pw_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000).hex()
        self._registered_users[sanitized] = f"{salt}:{pw_hash}"
        return sanitized

    def authenticate(self, username: str, password: str) -> Optional[str]:
        if username not in self._registered_users:
            return None
        stored = self._registered_users[username]
        salt, stored_hash = stored.split(':', 1)
        pw_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000).hex()
        if not hmac.compare_digest(pw_hash, stored_hash):
            return None
        # Generate token
        player_id = str(uuid.uuid4())
        token_data = f"{player_id}:{time.time()}:{secrets.token_hex(16)}"
        signature = hmac.new(self._secret, token_data.encode('utf-8'), hashlib.sha256).hexdigest()
        token = f"{token_data}:{signature}"
        expiry = time.time() + TOKEN_EXPIRY_SECONDS
        self._active_tokens[token] = (player_id, expiry)
        return token

    def validate_token(self, token: str) -> Optional[str]:
        if token not in self._active_tokens:
            return None
        player_id, expiry = self._active_tokens[token]
        if time.time() > expiry:
            del self._active_tokens[token]
            return None
        # Verify HMAC
        parts = token.rsplit(':', 1)
        if len(parts) != 2:
            return None
        token_data, signature = parts
        expected_sig = hmac.new(self._secret, token_data.encode('utf-8'), hashlib.sha256).hexdigest()
        if not hmac.compare_digest(signature, expected_sig):
            del self._active_tokens[token]
            return None
        return player_id

    def revoke_token(self, token: str):
        self._active_tokens.pop(token, None)

    def cleanup_expired(self):
        now = time.time()
        expired = [t for t, (_, exp) in self._active_tokens.items() if now > exp]
        for t in expired:
            del self._active_tokens[t]


class RateLimiter:
    """Per-client rate limiter using token bucket algorithm."""

    def __init__(self, max_tokens: int = 60, refill_rate: float = 30.0):
        self._max_tokens = max_tokens
        self._refill_rate = refill_rate
        self._buckets: dict[str, tuple[float, float]] = {}  # client_id -> (tokens, last_refill)

    def allow(self, client_id: str) -> bool:
        now = time.time()
        if client_id not in self._buckets:
            self._buckets[client_id] = (self._max_tokens - 1, now)
            return True
        tokens, last_refill = self._buckets[client_id]
        elapsed = now - last_refill
        tokens = min(self._max_tokens, tokens + elapsed * self._refill_rate)
        if tokens >= 1:
            self._buckets[client_id] = (tokens - 1, now)
            return True
        self._buckets[client_id] = (tokens, now)
        return False

    def remove(self, client_id: str):
        self._buckets.pop(client_id, None)


class InputValidator:
    """Validates and sanitizes client inputs."""

    @staticmethod
    def validate_movement(dx: float, dy: float) -> tuple[float, float]:
        try:
            dx = float(dx)
            dy = float(dy)
        except (TypeError, ValueError):
            return 0.0, 0.0
        if not (math.isfinite(dx) and math.isfinite(dy)):
            return 0.0, 0.0
        magnitude = math.sqrt(dx * dx + dy * dy)
        if magnitude > MAX_SPEED:
            scale = MAX_SPEED / magnitude
            dx *= scale
            dy *= scale
        return round(dx, 4), round(dy, 4)

    @staticmethod
    def validate_rotation(rotation: float) -> float:
        try:
            rotation = float(rotation)
        except (TypeError, ValueError):
            return 0.0
        if not math.isfinite(rotation):
            return 0.0
        return rotation % (2 * math.pi)

    @staticmethod
    def validate_weapon(weapon: str) -> Optional[str]:
        if weapon in WEAPON_CONFIGS:
            return weapon
        return None

    @staticmethod
    def validate_fire_target(x: float, y: float) -> Optional[tuple[float, float]]:
        try:
            x = float(x)
            y = float(y)
        except (TypeError, ValueError):
            return None
        if not (math.isfinite(x) and math.isfinite(y)):
            return None
        x = max(0, min(MAP_WIDTH, x))
        y = max(0, min(MAP_HEIGHT, y))
        return round(x, 2), round(y, 2)


class GameWorld:
    """Manages the game world state including obstacles."""

    def __init__(self):
        self.obstacles: list[Obstacle] = []
        self._generate_obstacles()

    def _generate_obstacles(self):
        """Generate static obstacles for the map."""
        import random
        rng = random.Random(42)  # Deterministic seed for consistent maps
        for i in range(50):
            self.obstacles.append(Obstacle(
                obstacle_id=f"obs_{i}",
                position=Vector2(rng.uniform(100, MAP_WIDTH - 100), rng.uniform(100, MAP_HEIGHT - 100)),
                width=rng.uniform(20, 80),
                height=rng.uniform(20, 80),
            ))

    def get_obstacles_dict(self) -> list[dict]:
        return [o.to_dict() for o in self.obstacles]


class BattleRoyaleServer:
    """Main game server handling connections, game logic, and state broadcasting."""

    def __init__(self):
        self.players: dict[str, Player] = {}
        self.clients: dict[str, asyncio.StreamWriter] = {}  # player_id -> writer
        self.client_tokens: dict[str, str] = {}  # player_id -> token
        self.client_names: dict[str, str] = {}  # player_id -> username
        self.zone = Zone()
        self.world = GameWorld()
        self.events: list[GameEvent] = []
        self.auth = AuthManager(SERVER_SECRET)
        self.rate_limiter = RateLimiter()
        self.tick_count = 0
        self.game_started = False
        self.game_over = False
        self.last_zone_shrink = 0.0
        self._lock = asyncio.Lock()
        self._running = False

    def _spawn_position(self) -> Vector2:
        """Generate a spawn position within the initial zone."""
        import random
        angle = random.uniform(0, 2 * math.pi)
        radius = random.uniform(0, self.zone.radius * 0.8)
        return Vector2(
            x=self.zone.center.x + radius * math.cos(angle),
            y=self.zone.center.y + radius * math.sin(angle),
        )

    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        """Handle a single client connection."""
        addr = writer.get_extra_info('peername')
        client_id = str(uuid.uuid4())
        player_id = None
        logger.info(f"New connection from {addr}, client_id={client_id}")

        try:
            # Authentication phase
            player_id = await self._authenticate_client(reader, writer, client_id)
            if not player_id:
                return

            # Send initial game state (map, obstacles)
            await self._send_message(writer, {
                "type": "init",
                "player_id": player_id,
                "map": {
                    "width": MAP_WIDTH,
                    "height": MAP_HEIGHT,
                    "obstacles": self.world.get_obstacles_dict(),
                },
                "zone": self.zone.to_dict(),
                "weapon_configs": WEAPON_CONFIGS,
            })

            # Main client loop
            while self._running:
                try:
                    data = await asyncio.wait_for(reader.readline(), timeout=30.0)
                except asyncio.TimeoutError:
                    # Send keepalive ping
                    try:
                        await self._send_message(writer, {"type": "ping", "t": time.time()})
                    except (ConnectionError, OSError):
                        break
                    continue

                if not data:
                    break

                if len(data) > MAX_MESSAGE_SIZE:
                    logger.warning(f"Message too large from {player_id}, dropping")
                    continue

                if not self.rate_limiter.allow(client_id):
                    logger.warning(f"Rate limit exceeded for {player_id}")
                    await self._send_message(writer, {"type": "error", "message": "rate_limited"})
                    continue

                try:
                    message = json.loads(data.decode('utf-8').strip())
                except (json.JSONDecodeError, UnicodeDecodeError):
                    logger.warning(f"Invalid message from {player_id}")
                    continue

                await self._process_message(player_id, message)

        except (ConnectionError, OSError) as e:
            logger.info(f"Connection lost for {player_id or client_id}: {e}")
        except Exception as e:
            logger.error(f"Unexpected error for {player_id or client_id}: {e}", exc_info=True)
        finally:
            await self._disconnect_player(player_id, client_id)
            try:
                writer.close()
                await writer.wait_closed()
            except Exception:
                pass

    async def _authenticate_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter, client_id: str) -> Optional[str]:
        """Authenticate a client and return player_id or None."""
        try:
            data = await asyncio.wait_for(reader.readline(), timeout=10.0)
        except asyncio.TimeoutError:
            await self._send_message(writer, {"type": "error", "message": "auth_timeout"})
            return None

        if not data or len(data) > MAX_MESSAGE_SIZE:
            return None

        try:
            msg = json.loads(data.decode('utf-8').strip())
        except (json.JSONDecodeError, UnicodeDecodeError):
            await self._send_message(writer, {"type": "error", "message": "invalid_auth"})
            return None

        msg_type = msg.get("type")

        if msg_type == "register":
            username = msg.get("username", "")
            password = msg.get("password", "")
            if not isinstance(username, str) or not isinstance(password, str):
                await self._send_message(writer, {"type": "error", "message": "invalid_credentials"})
                return None
            if len(password) < 8:
                await self._send_message(writer, {"type": "error", "message": "password_too_short"})
                return None
            result = self.auth.register(username, password)
            if not result:
                await self._send_message(writer, {"type": "error", "message": "registration_failed"})
                return None
            # Auto-login after registration
            token = self.auth.authenticate(username, password)
            if not token:
                await self._send_message(writer, {"type": "error", "message": "auth_failed"})
                return None
            player_id = self.auth.validate_token(token)
            if not player_id:
                return None
            await self._setup_player(player_id, username, token, writer)
            await self._send_message(writer, {"type": "auth_ok", "token": token, "player_id": player_id})
            return player_id

        elif msg_type == "login":
            username = msg.get("username", "")
            password = msg.get("password", "")
            if not isinstance(username, str) or not isinstance(password, str):
                await self._send_message(writer, {"type": "error", "message": "invalid_credentials"})
                return None
            token = self.auth.authenticate(username, password)
            if not token:
                await self._send_message(writer, {"type": "error", "message": "auth_failed"})
                return None
            player_id = self.auth.validate_token(token)
            if not player_id:
                return None
            await self._setup_player(player_id, username, token, writer)
            await self._send_message(writer, {"type": "auth_ok", "token": token, "player_id": player_id})
            return player_id

        elif msg_type == "reconnect":
            token = msg.get("token", "")
            if not isinstance(token, str):
                await self._send_message(writer, {"type": "error", "message": "invalid_token"})
                return None
            player_id = self.auth.validate_token(token)
            if not player_id:
                await self._send_message(writer, {"type": "error", "message": "invalid_token"})
                return None
            # Reconnect existing player
            async with self._lock:
                if player_id in self.players:
                    self.clients[player_id] = writer
                    await self._send_message(writer, {"type": "auth_ok", "token": token, "player_id": player_id})
                    return player_id
            await self._send_message(writer, {"type": "error", "message": "no_session"})
            return None

        await self._send_message(writer, {"type": "error", "message": "unknown_auth_type"})
        return None

    async def _setup_player(self, player_id: str, username: str, token: str, writer: asyncio.StreamWriter):
        """Set up a new player in the game."""
        async with self._lock:
            if len(self.players) >= MAX_PLAYERS:
                await self._send_message(writer, {"type": "error", "message": "server_full"})
                return
            spawn = self._spawn_position()
            player = Player(
                player_id=player_id,
                name=username,
                position=spawn,
            )
            self.players[player_id] = player
            self.clients[player_id] = writer
            self.client_tokens[player_id] = token
            self.client_names[player_id] = username

            self.events.append(GameEvent(
                event_type="player_joined",
                data={"player_id": player_id, "name": username},
            ))
            logger.info(f"Player {username} ({player_id}) joined. Total: {len(self.players)}")

    async def _disconnect_player(self, player_id: Optional[str], client_id: str):
        """Clean up when a player disconnects."""
        self.rate_limiter.remove(client_id)
        if player_id:
            async with self._lock:
                if player_id in self.clients:
                    del self.clients[player_id]
                if player_id in self.client_tokens:
                    self.auth.revoke_token(self.client_tokens[player_id])
                    del self.client_tokens[player_id]
                if player_id in self.players:
                    self.players[player_id].state = PlayerState.DEAD
                    self.events.append(GameEvent(
                        event_type="player_disconnected",
                        data={"player_id": player_id, "name": self.client_names.get(player_id, "unknown")},
                    ))
                    del self.players[player_id]
                self.client_names.pop(player_id, None)
                logger.info(f"Player {player_id} disconnected. Total: {len(self.players)}")

    async def _process_message(self, player_id: str, message: dict):
        """Process a validated client message."""
        msg_type = message.get("type")
        if not isinstance(msg_type, str):
            return

        async with self._lock:
            player = self.players.get(player_id)
            if not player:
                return

            if msg_type == "move":
                if player.state != PlayerState.ALIVE:
                    return
                dx, dy = InputValidator.validate_movement(
                    message.get("dx", 0),
                    message.get("dy", 0),
                )
                rotation = InputValidator.validate_rotation(message.get("rotation", player.rotation))
                input_seq = message.get("seq", 0)
                if not isinstance(input_seq, int):
                    input_seq = 0

                new_x = player.position.x + dx
                new_y = player.position.y + dy
                new_pos = Vector2(new_x, new_y).clamp(0, 0, MAP_WIDTH, MAP_HEIGHT)

                # Collision check with obstacles
                if not self._check_obstacle_collision(new_pos, 10.0):
                    player.position = new_pos

                player.velocity = Vector2(dx, dy)
                player.rotation = rotation
                player.last_input_seq = input_seq

            elif msg_type == "fire":
                if player.state != PlayerState.ALIVE:
                    return
                target = message.get("target", {})
                if not isinstance(target, dict):
                    return
                validated = InputValidator.validate_fire_target(
                    target.get("x", 0),
                    target.get("y", 0),
                )
                if not validated:
                    return

                weapon_cfg = WEAPON_CONFIGS.get(player.weapon)
                if not weapon_cfg:
                    return

                now = time.time()
                if now - player.last_fire_time < weapon_cfg["fire_rate"]:
                    return

                if player.ammo.get(player.weapon, 0) <= 0:
                    return

                player.ammo[player.weapon] -= 1
                player.last_fire_time = now

                target_pos = Vector2(validated[0], validated[1])
                self._process_shot(player, target_pos, weapon_cfg)

            elif msg_type == "switch_weapon":
                weapon = InputValidator.validate_weapon(message.get("weapon", ""))
                if weapon:
                    player.weapon = weapon

            elif msg_type == "pong":
                pass  # Keepalive response

    def _check_obstacle_collision(self, pos: Vector2, radius: float) -> bool:
        """Check if a position collides with any obstacle."""
        for obs in self.world.obstacles:
            # Simple AABB collision
            half_w = obs.width / 2
            half_h = obs.height / 2
            closest_x = max(obs.position.x - half_w, min(pos.x, obs.position.x + half_w))
            closest_y = max(obs.position.y - half_h, min(pos.y, obs.position.y + half_h))
            dist = math.sqrt((pos.x - closest_x) ** 2 + (pos.y - closest_y) ** 2)
            if dist < radius:
                return True
        return False

    def _process_shot(self, shooter: Player, target_pos: Vector2, weapon_cfg: dict):
        """Process a shot from a player. Server-authoritative hit detection."""
        weapon_range = weapon_cfg["range"]
        damage = weapon_cfg["damage"]

        # Direction from shooter to target
        dx = target_pos.x - shooter.position.x
        dy = target_pos.y - shooter.position.y
        dist_to_target = math.sqrt(dx * dx + dy * dy)

        if dist_to_target == 0:
            return

        # Normalize direction
        dir_x = dx / dist_to_target
        dir_y = dy / dist_to_target

        # Check all alive players for hits (ray-cast style)
        hit_player = None
        hit_dist = weapon_range

        for pid, other in self.players.items():
            if pid == shooter.player_id or other.state != PlayerState.ALIVE:
                continue

            # Project other player onto the ray
            to_other_x = other.position.x - shooter.position.x
            to_other_y = other.position.y - shooter.position.y
            projection = to_other_x * dir_x + to_other_y * dir_y

            if projection < 0 or projection > hit_dist:
                continue

            # Perpendicular distance
            closest_x = shooter.position.x + dir_x * projection
            closest_y = shooter.position.y + dir_y * projection
            perp_dist = math.sqrt(
                (other.position.x - closest_x) ** 2 +
                (other.position.y - closest_y) ** 2
            )

            player_hitbox_radius = 15.0
            if perp_dist <= player_hitbox_radius:
                # Check line of sight (obstacle blocking)
                if not self._is_blocked_by_obstacle(shooter.position, other.position):
                    hit_dist = projection
                    hit_player = other

        # Record fire event
        fire_event_data = {
            "shooter_id": shooter.player_id,
            "weapon": shooter.weapon,
            "origin": shooter.position.to_dict(),
            "target": target_pos.to_dict(),
        }

        if hit_player:
            hit_player.health = max(0, hit_player.health - damage)
            fire_event_data["hit_player_id"] = hit_player.player_id
            fire_event_data["damage"] = damage

            if hit_player.health <= 0:
                hit_player.state = PlayerState.DEAD
                shooter.kills += 1
                self.events.append(GameEvent(
                    event_type="player_killed",
                    data={
                        "killer_id": shooter.player_id,
                        "killer_name": shooter.name,
                        "victim_id": hit_player.player_id,
                        "victim_name": hit_player.name,
                        "weapon": shooter.weapon,
                    },
                ))
                logger.info(f"{shooter.name} killed {hit_player.name} with {shooter.weapon}")

        self.events.append(GameEvent(event_type="shot_fired", data=fire_event_data))

    def _is_blocked_by_obstacle(self, from_pos: Vector2, to_pos: Vector2) -> bool:
        """Check if line of sight between two positions is blocked by obstacles."""
        dx = to_pos.x - from_pos.x
        dy = to_pos.y - from_pos.y
        dist = math.sqrt(dx * dx + dy * dy)
        if dist == 0:
            return False

        steps = int(dist / 10)  # Check every 10 units
        steps = max(steps, 1)

        for i in range(1, steps):
            t = i / steps
            check_x = from_pos.x + dx * t
            check_y = from_pos.y + dy * t
            check_pos = Vector2(check_x, check_y)

            for obs in self.world.obstacles:
                half_w = obs.width / 2
                half_h = obs.height / 2
                if (obs.position.x - half_w <= check_x <= obs.position.x + half_w and
                        obs.position.y - half_h <= check_y <= obs.position.y + half_h):
                    return True
        return False

    async def game_loop(self):
        """Main server game loop running at TICK_RATE."""
        self._running = True
        tick_interval = 1.0 / TICK_RATE
        self.last_zone_shrink = time.time()
        logger.info(f"Game loop started at {TICK_RATE} ticks/second")

        while self._running:
            tick_start = time.time()

            async with self._lock:
                self._update_zone()
                self._apply_zone_damage()
                self._check_win_condition()
                await self._broadcast_state()
                self.events.clear()
                self.tick_count += 1

            elapsed = time.time() - tick_start
            sleep_time = max(0, tick_interval - elapsed)
            await asyncio.sleep(sleep_time)

    def _update_zone(self):
        """Update the zone shrinking."""
        now = time.time()
        if now - self.last_zone_shrink >= ZONE_SHRINK_INTERVAL:
            self.zone.target_radius = max(50.0, self.zone.target_radius - ZONE_SHRINK_AMOUNT)
            self.last_zone_shrink = now
            self.events.append(GameEvent(
                event_type="zone_shrinking",
                data={"target_radius": self.zone.target_radius},
            ))

        if self.zone.radius > self.zone.target_radius:
            self.zone.radius = max(
                self.zone.target_radius,
                self.zone.radius - self.zone.shrink_speed / TICK_RATE
            )

    def _apply_zone_damage(self):
        """Apply damage to players outside the zone."""
        for player in self.players.values():
            if player.state == PlayerState.ALIVE and not self.zone.is_inside(player.position):
                player.health = max(0, player.health - ZONE_DAMAGE_PER_TICK)
                if player.health <= 0:
                    player.state = PlayerState.DEAD
                    self.events.append(GameEvent(
                        event_type="player_killed",
                        data={
                            "killer_id": "zone",
                            "killer_name": "The Zone",
                            "victim_id": player.player_id,
                            "victim_name": player.name,
                            "weapon": "zone",
                        },
                    ))

    def _check_win_condition(self):
        """Check if there's a winner."""
        alive_players = [p for p in self.players.values() if p.state == PlayerState.ALIVE]
        if len(self.players) > 1 and len(alive_players) <= 1:
            if alive_players:
                winner = alive_players[0]
                self.events.append(GameEvent(
                    event_type="game_over",
                    data={
                        "winner_id": winner.player_id,
                        "winner_name": winner.name,
                        "kills": winner.kills,
                    },
                ))
                self.game_over = True
                logger.info(f"Game over! Winner: {winner.name} with {winner.kills} kills")

    async def _broadcast_state(self):
        """Broadcast full game state to all connected clients.
        
        Clients are responsible for filtering based on distance and line of sight.
        This approach optimizes for client-side rendering flexibility.
        """
        # Build full state snapshot
        all_players = {pid: p.to_dict() for pid, p in self.players.items()}
        events_list = [e.to_dict() for e in self.events]

        state = {
            "type": "state",
            "tick": self.tick_count,
            "timestamp": time.time(),
            "players": all_players,
            "zone": self.zone.to_dict(),
            "events": events_list,
            "alive_count": sum(1 for p in self.players.values() if p.state == PlayerState.ALIVE),
        }

        # Send personalized state to each client (includes their input ack)
        disconnected = []
        for player_id, writer in self.clients.items():
            try:
                player = self.players.get(player_id)
                personalized_state = state.copy()
                if player:
                    personalized_state["your_state"] = player.to_dict()
                    personalized_state["ack_seq"] = player.last_input_seq
                await self._send_message(writer, personalized_state)
            except (ConnectionError, OSError):
                disconnected.append(player_id)

        # Clean up disconnected clients (will be fully cleaned in handle_client finally)
        for pid in disconnected:
            self.clients.pop(pid, None)

    @staticmethod
    async def _send_message(writer: asyncio.StreamWriter, message: dict):
        """Send a JSON message to a client, terminated by newline."""
        data = json.dumps(message, separators=(',', ':')) + '\n'
        writer.write(data.encode('utf-8'))
        await writer.drain()

    async def start(self, use_tls: bool = False):
        """Start the game server."""
        ssl_context = None
        if use_tls:
            ssl_context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
            ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2
            try:
                ssl_context.load_cert_chain('server.crt', 'server.key')
                logger.info("TLS enabled")
            except FileNotFoundError:
                logger.warning("TLS cert/key not found, running without TLS")
                ssl_context = None

        server = await asyncio.start_server(
            self.handle_client,
            SERVER_HOST,
            SERVER_PORT,
            ssl=ssl_context,
            limit=MAX_MESSAGE_SIZE * 2,
        )

        addr = server.sockets[0].getsockname()
        logger.info(f"Battle Royale Server running on {addr}")

        # Start game loop
        game_task = asyncio.create_task(self.game_loop())

        # Periodic auth cleanup
        async def auth_cleanup():
            while self._running:
                await asyncio.sleep(60)
                self.auth.cleanup_expired()

        cleanup_task = asyncio.create_task(auth_cleanup())

        try:
            async with server:
                await server.serve_forever()
        except asyncio.CancelledError:
            pass
        finally:
            self._running = False
            game_task.cancel()
            cleanup_task.cancel()
            try:
                await game_task
            except asyncio.CancelledError:
                pass
            try:
                await cleanup_task
            except asyncio.CancelledError:
                pass
            logger.info("Server shut down")


# --- Example Client for Testing ---
class TestClient:
    """Simple test client to verify server functionality."""

    def __init__(self, host: str = "127.0.0.1", port: int = SERVER_PORT):
        self.host = host
        self.port = port
        self.reader: Optional[asyncio.StreamReader] = None
        self.writer: Optional[asyncio.StreamWriter] = None
        self.player_id: Optional[str] = None
        self.token: Optional[str] = None

    async def connect(self):
        self.reader, self.writer = await asyncio.open_connection(self.host, self.port)

    async def send(self, message: dict):
        data = json.dumps(message) + '\n'
        self.writer.write(data.encode('utf-8'))
        await self.writer.drain()

    async def receive(self) -> dict:
        data = await asyncio.wait_for(self.reader.readline(), timeout=10.0)
        return json.loads(data.decode('utf-8').strip())

    async def register_and_login(self, username: str, password: str):
        await self.send({"type": "register", "username": username, "password": password})
        response = await self.receive()
        if response.get("type") == "auth_ok":
            self.player_id = response["player_id"]
            self.token = response["token"]
            # Receive init message
            init_msg = await self.receive()
            return init_msg
        return response

    async def close(self):
        if self.writer:
            self.writer.close()
            await self.writer.wait_closed()


async def run_demo():
    """Run a demo with server and test clients."""
    server = BattleRoyaleServer()

    # Start server in background
    server_task = asyncio.create_task(server.start())

    # Wait for server to start
    await asyncio.sleep(1)

    # Create test clients
    clients = []
    for i in range(3):
        client = TestClient()
        await client.connect()
        init = await client.register_and_login(f"Player{i}", f"password{i}secure")
        logger.info(f"Client {i} connected: player_id={client.player_id}")
        clients.append(client)

    # Simulate some gameplay
    for tick in range(10):
        # Each client sends movement
        for i, client in enumerate(clients):
            await client.send({
                "type": "move",
                "dx": 5.0 * (i + 1),
                "dy": 3.0,
                "rotation": 0.5 * i,
                "seq": tick,
            })

        # Client 0 fires at tick 5
        if tick == 5:
            await clients[0].send({
                "type": "fire",
                "target": {"x": 500.0, "y": 500.0},
            })

        # Receive state updates
        for client in clients:
            try:
                state = await asyncio.wait_for(client.reader.readline(), timeout=1.0)
                if state:
                    parsed = json.loads(state.decode('utf-8').strip())
                    if parsed.get("type") == "state":
                        alive = parsed.get("alive_count", 0)
                        players = parsed.get("players", {})
                        logger.info(f"Tick {parsed.get('tick')}: {len(players)} players, {alive} alive")
            except asyncio.TimeoutError:
                pass

        await asyncio.sleep(0.1)

    # Cleanup
    for client in clients:
        await client.close()

    server._running = False
    server_task.cancel()
    try:
        await server_task
    except asyncio.CancelledError:
        pass

    logger.info("Demo complete")


if __name__ == "__main__":
    import sys

    if "--demo" in sys.argv:
        asyncio.run(run_demo())
    else:
        server = BattleRoyaleServer()
        try:
            asyncio.run(server.start(use_tls="--tls" in sys.argv))
        except KeyboardInterrupt:
            logger.info("Server interrupted")